document.addEventListener('DOMContentLoaded', () => {
    const citeElements = document.querySelectorAll('cite[data-ref]');
    const usedKeys = [];

    // Step 1: Replace inline <cite data-ref="key"></cite> with [1], [2]
    citeElements.forEach(el => {
        const key = el.getAttribute('data-ref');
        if (bibData[key]) {
            if (!usedKeys.includes(key)) {
                usedKeys.push(key);
            }
            const refNum = usedKeys.indexOf(key) + 1;
            // Create clickable superscript bracket like LaTeX
            el.outerHTML = `<a href="#ref-${key}" class="text-blue-600 hover:underline align-super text-sm">[${refNum}]</a>`;
        } else {
            el.outerHTML = `<span style="color:red; font-weight:bold;">[?]</span>`;
            console.warn(`Citation key "${key}" not found in ref.bib`);
        }
    });

    // Step 2: Build the bibliography section at the bottom
    const bibContainer = document.getElementById('bibliography');
    if (bibContainer && usedKeys.length > 0) {
        let html = '<ol class="space-y-4 list-decimal pl-5 text-sm">\n';
        usedKeys.forEach(key => {
            html += `  <li id="ref-${key}" class="pl-2">\n    ${bibData[key]}\n  </li>\n`;
        });
        html += '</ol>';
        bibContainer.innerHTML = html;
    }
});
